const { execSync } = require('child_process');

const query = $input.first().json.query || 'test';
const safeQuery = query.replace(/"/g, '\\"').replace(/\n/g, ' ');

const prompt = `Analyze this research query and return ONLY a JSON object (no markdown, no explanation) with these fields: sub_questions (array of objects with id, question, search_type), search_terms (object with primary_de, primary_en arrays), sources (array from: kb, web, deep, social, academic, miniflux), scope (object with time_range, languages), domain_classification (one of: tech, finance, academic, product_comparison, travel, general), mode (one of: quick, standard, deep). Rules: quick=simple facts, standard=comparisons/analysis, deep=high stakes. Query: ${safeQuery}`;

try {
  const result = execSync(`gemini -p "${prompt.replace(/"/g, '\\"')}"`, {
    encoding: 'utf-8',
    timeout: 120000,
    env: { ...process.env, PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin:' + (process.env.PATH || ''), HOME: '/home/clawd' },
    cwd: '/home/clawd'
  });

  return [{ json: { stdout: result, exitCode: 0, query: query } }];
} catch (error) {
  return [{ json: { stdout: error.stdout || '', stderr: error.stderr || error.message, exitCode: error.status || 1, query: query } }];
}

// Parse Gemini CLI JSON output — robust extraction
const raw = $input.first().json.stdout || '';

// Gemini CLI gibt stderr-Zeilen vor dem JSON aus (ERROR, Server, Loaded etc.)
// Diese Zeilen filtern und nur das JSON extrahieren
let jsonStr = '';

// Versuch 1: Markdown JSON Block
const mdMatch = raw.match(/```json\n?([\s\S]*?)\n?```/);
if (mdMatch) {
  jsonStr = mdMatch[1];
} else {
  // Versuch 2: Erstes valides JSON-Objekt finden
  const lines = raw.split('\n');
  let braceCount = 0;
  let jsonStart = -1;
  let jsonEnd = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    // Stderr-Zeilen ueberspringen
    if (line.startsWith('[ERROR]') || line.startsWith('Loaded ') || line.startsWith('Server ') || line.trim() === '') continue;

    if (jsonStart === -1 && line.trim().startsWith('{')) {
      jsonStart = i;
    }
    if (jsonStart >= 0) {
      for (const ch of line) {
        if (ch === '{') braceCount++;
        if (ch === '}') braceCount--;
      }
      if (braceCount === 0 && jsonStart >= 0) {
        jsonEnd = i;
        break;
      }
    }
  }

  if (jsonStart >= 0 && jsonEnd >= 0) {
    jsonStr = lines.slice(jsonStart, jsonEnd + 1).join('\n');
  } else {
    jsonStr = raw;
  }
}

let parsed;
try {
  parsed = JSON.parse(jsonStr.trim());
} catch (e) {
  // Fallback: Minimalen Plan erzeugen
  const query = $('Execute Workflow Trigger').first().json.query || '';
  parsed = {
    sub_questions: [{id: 'sq-1', question: query, search_type: 'web'}],
    search_terms: {primary_de: [query], primary_en: [query]},
    sources: ['web', 'kb'],
    scope: {time_range: 'last_year', languages: ['de', 'en']},
    domain_classification: 'general',
    mode: 'quick'
  };
}

// Fehlende Felder mit Defaults auffuellen
if (!parsed.scope) parsed.scope = {time_range: 'last_year', languages: ['de', 'en']};
if (!parsed.sources) parsed.sources = ['web', 'kb'];
if (!parsed.search_terms) parsed.search_terms = {primary_de: [], primary_en: []};

// Valide Modi
const validModes = ['quick', 'standard', 'deep'];
if (!validModes.includes(parsed.mode)) parsed.mode = 'standard';

// Mode Override
const query = $('Execute Workflow Trigger').first().json.query || '';
const modeOverride = $('Execute Workflow Trigger').first().json.mode_override || null;
if (modeOverride && validModes.includes(modeOverride)) {
  parsed.mode = modeOverride;
} else if (query.match(/\[deep\]/i)) {
  parsed.mode = 'deep';
} else if (query.match(/\[quick\]/i)) {
  parsed.mode = 'quick';
}

return [{
  json: {
    search_plan: parsed,
    mode: parsed.mode,
    query: query,
    language: $('Execute Workflow Trigger').first().json.language || 'de'
  }
}];

const { execSync } = require('child_process');

const query = $input.first().json.query || $input.first().json.search_plan?.sub_questions?.[0]?.question || 'test';

try {
  const result = execSync(`python3 /home/clawd/.openclaw/workspace/scripts/kb-search.py "${query.replace(/"/g, '\\"')}" --limit 3`, {
    encoding: 'utf-8',
    timeout: 30000,
    env: { ...process.env, PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin:' + (process.env.PATH || '') },
    cwd: '/home/clawd'
  });

  return [{ json: { stdout: result, exitCode: 0, query: query } }];
} catch (error) {
  // KB-Search Fehler ist kein Blocker
  return [{ json: { stdout: error.stdout || '', stderr: error.stderr || error.message, exitCode: error.status || 1, query: query } }];
}

// Combine search_plan + KB results + mode into final output
const planData = $('Parse Codex Output').first().json;
const kbRaw = $input.first().json.stdout || '';
const kbExitCode = $input.first().json.exitCode;

// KB-Output parsen
let kbExisting = false;
let kbHitsCount = 0;
let kbHits = [];

try {
  // kb-search.py gibt JSON aus
  const kbParsed = JSON.parse(kbRaw.trim());
  if (Array.isArray(kbParsed)) {
    kbHits = kbParsed;
    kbHitsCount = kbParsed.length;
    kbExisting = kbHitsCount > 0;
  } else if (kbParsed.results) {
    kbHits = kbParsed.results;
    kbHitsCount = kbParsed.results.length;
    kbExisting = kbHitsCount > 0;
  }
} catch (e) {
  // KB-Search fehlgeschlagen oder kein JSON — kein Blocker
  kbExisting = false;
  kbHitsCount = 0;
}

return [{
  json: {
    search_plan: planData.search_plan,
    mode: planData.mode,
    query: planData.query,
    language: planData.language,
    kb_existing: kbExisting,
    kb_hits_count: kbHitsCount,
    kb_hits: kbHits
  }
}];
